(() => {
  const isRobot = /Are you a robot/i.test(document.title)
    || /unusual activity/i.test(document.body.innerText)
    || /click the box below to let us know you're not a robot/i.test(document.body.innerText);

  if (isRobot) {
    throw new Error('Bloomberg served bot-protection page');
  }

  const raw = document.querySelector('#__NEXT_DATA__')?.textContent;
  if (!raw) {
    throw new Error('No __NEXT_DATA__ found on page');
  }

  const parsed = JSON.parse(raw);
  const story = parsed?.props?.pageProps?.story;
  if (!story) {
    throw new Error('No story data found in __NEXT_DATA__');
  }

  const title = story.headline || story.seoHeadline || story.seoTitle || document.querySelector('h1')?.textContent?.trim() || document.title;
  const summary = story.summary || story.socialDescription || story.seoDescription || document.querySelector('meta[name="description"]')?.getAttribute('content') || '';
  const url = story.url || story.readingUrl || location.href;

  const body = story.body;
  const content = renderBody(body);

  const mediaLinks = extractMediaLinks(story);

  function renderBody(body) {
    const blocks = Array.isArray(body?.content) ? body.content : [];
    return blocks.map(b => renderBlock(b)).filter(Boolean).join('\n\n').trim();
  }

  function renderBlock(block) {
    if (!block || typeof block !== 'object') return '';
    if (block.type === 'paragraph') return renderInline(block.content || []);
    if (block.type === 'heading') {
      const text = renderInline(block.content || []);
      return text ? '## ' + text : '';
    }
    if (Array.isArray(block.content)) {
      return block.content.map(c => renderBlock(c)).filter(Boolean).join('\n');
    }
    return '';
  }

  function renderInline(nodes) {
    return (nodes || []).map(n => {
      if (typeof n === 'string') return n;
      if (n?.type === 'text') return n.value || '';
      if (Array.isArray(n?.content)) return renderInline(n.content);
      return n?.value || '';
    }).join('');
  }

  function extractMediaLinks(story) {
    const urls = [];
    if (story.ledeImageUrl) urls.push(story.ledeImageUrl);
    if (story.socialImageUrl) urls.push(story.socialImageUrl);
    return urls.join(', ');
  }

  return [{ title, summary, link: url, mediaLinks, content }];
})()
